// mm/src/api/uploadDocument.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';
const DEFAULT_UPLOAD_DOC_URL =
  'https://manuscriptmagic.fowkes.xyz/services/uploadDocument.php';

function getUploadDocumentUrl() {
  return API_BASE ? `${API_BASE}/documents/upload` : DEFAULT_UPLOAD_DOC_URL;
}


function getAccessToken() {
  return localStorage.getItem('mm_accessToken') || '';
}

export const uploadDocument = (file, onProgress) => {
  const accessToken = getAccessToken();

  // DEV MOCK: no backend configured (matches style of upload.js)
  if (!API_BASE) {
    return new Promise((resolve) => {
      const total = file?.size || 1024 * 400;
      let loaded = 0;

      const interval = setInterval(() => {
        loaded += total / 12;
        const pct = Math.min(100, Math.round((loaded / total) * 100));
        if (onProgress) onProgress(pct);

        if (pct >= 100) {
          clearInterval(interval);
          resolve({
            data: {
              success: true,
              message: 'Mock uploadDocument success',
              documentId: `mock_doc_${Date.now()}`,
              filePath: `/mock/docs/${encodeURIComponent(file?.name || 'document')}`,
            },
          });
        }
      }, 120);
    });
  }


  const url = getUploadDocumentUrl();

  const form = new FormData();
  form.append('document', file); 

  return axios.post(url, form, {
    headers: {
      'Content-Type': 'multipart/form-data',
      Authorization: `Bearer ${accessToken}`, 
    },
    onUploadProgress: (evt) => {
      if (onProgress && evt.total) {
        const pct = Math.round((evt.loaded * 100) / evt.total);
        onProgress(pct);
      }
    },
  });
};
